                FromX: h.X,
                FromY: h.Y,
                ToX:   tx,
                ToY:   ty,
                Kind:  "step",
                Legal: legal && visible,
        }
        h.X, h.Y = tx, ty
        w.Hostile[idx] = h
        return row, true
}
